action.file_text:
lexer grammar SYsULexer;

// Keywords
Const     : 'const';
Int       : 'int';
Void      : 'void';
Return    : 'return';
If        : 'if';
Else      : 'else';
While     : 'while';
Break     : 'break';
Continue  : 'continue';

// Punctuation / brackets
LeftParen    : '(';
RightParen   : ')';
LeftBracket  : '[';
RightBracket : ']';
LeftBrace    : '{';
RightBrace   : '}';

Semi  : ';';
Comma : ',';

// Operators
Plus         : '+';
Minus        : '-';
Star         : '*';
Slash        : '/';
Percent      : '%';

Equal        : '=';
EqualEqual   : '==';
ExclaimEqual : '!=';
Less         : '<';
LessEqual    : '<=';
Greater      : '>';
GreaterEqual : '>=';
Exclaim      : '!';
AmpAmp       : '&&';
PipePipe     : '||';

// Identifier
Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

// Integer literals: hex, octal, decimal
Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   HexadecimalConstant
    |   DecimalConstant
    |   OctalConstant
    ;

fragment
HexadecimalConstant
    :   '0' [xX] HexadecimalDigit+
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

fragment
HexadecimalDigit
    :   [0-9a-fA-F]
    ;

// Line markers emitted by the preprocessor (`# linenum "file" flags*`).
// We need them to know the real (file, line) of each token, so put them on a
// hidden channel rather than skipping outright.
LineAfterPreprocessing
    :   '#' (' ' | '\t')* ~[\r\n]*
        -> channel(HIDDEN)
    ;

Whitespace
    :   [ \t]+
        -> channel(HIDDEN)
    ;

Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> channel(HIDDEN)
    ;

